function normalizeRow(r){const ps=psOf(r)||'ไม่ระบุ PS',tele=teleOf(r);const isTele=!!(tele&&!same(tele,ps))||isTeleFlag(r);return{date:dateOf(r),inv:invOf(r),type:typeOf(r),ps,store:storeOf(r),tele:isTele?(tele||ps||'Telesale'):'',isTele,code:codeOf(r),sku:skuOf(r),brand:brandOf(r),size:sizeOf(r),qty:qtyOf(r),amt:amtOf(r),unit:qtyOf(r)?amtOf(r)/qtyOf(r):N(r.unit)}}
