function group(rows){const m=new Map();rows.forEach(r=>{const k=[r.brand,r.size,r.code||r.sku,r.sku,r.type].join('|');let g=m.get(k);if(!g){g={poolKey:k,brand:r.brand,size:r.size,code:r.code,sku:r.sku,type:r.type,qty:0,amt:0,unit:r.unit||0,bills:new Set(),stores:new Map()};m.set(k,g)}g.qty+=N(r.qty);g.amt+=N(r.amt);g.unit=g.qty&&g.amt?g.amt/g.qty:g.unit;g.bills.add(r.inv);g.stores.set(r.store,(g.stores.get(r.store)||0)+N(r.qty))});return[...m.values()].sort((a,b)=>a.brand.localeCompare(b.brand,'th')||a.size.localeCompare(b.size,'th')||a.sku.localeCompare(b.sku,'th'))}
