function fill(){const rowsInDate=R.filter(r=>nonTele(r)&&(!filters.start||r.date>=filters.start)&&(!filters.end||r.date<=filters.end));opts('psSelect',uniq(rowsInDate.map(r=>r.ps)).sort((a,b)=>a.localeCompare(b,'th')),filters.ps,'ทั้งหมด');const stores=uniq(rowsInDate.filter(r=>!filters.ps||r.ps===filters.ps).map(r=>r.store)).sort((a,b)=>a.localeCompare(b,'th'));opts('storeSelect',stores,receiver,'เลือกร้านจริง');opts('brandSelect',uniq(rowsInDate.map(r=>r.brand)).sort((a,b)=>a.localeCompare(b,'th')),filters.brand,'ทั้งหมด');opts('typeSelect',uniq(rowsInDate.map(r=>r.type)).sort(),filters.type,'ทั้งหมด');if($('#startDate'))$('#startDate').value=filters.start;if($('#endDate'))$('#endDate').value=filters.end;if($('#q'))$('#q').value=filters.q;if($('#datePreview'))$('#datePreview').textContent=`${dlabel(filters.start)} - ${dlabel(filters.end)}`}
