function remain(g){let sent=0;Object.keys(send).filter(k=>k.startsWith(scopeHead())&&pkFromKey(k)===g.poolKey).forEach(k=>sent+=N(send[k]));return N(g.qty)-sent+N(add[rkey(g.poolKey)])-N(pull[rkey(g.poolKey)])}
function editTable(pool){const shown=pool.slice((page-1)*pageSize,page*pageSize);let h='<thead><tr><th>#</th><th>แบรนด์/ไซซ์</th><th>SKU</th><th>สินค้า</th><th>จำนวนออเดอร์รวม</th><th>จำนวนส่งร้านนี้</th><th>ของใส่เพิ่ม</th><th>ของดึงออก</th><th>คงเหลือรวม</th><th>ยอด</th></tr></thead><tbody>';if(!receiver)h+='<tr><td colspan="10" class="empty">กรุณาเลือกร้านจริงก่อนใส่จำนวนส่ง</td></tr>';shown.forEach((g,i)=>{const k=rkey(g.poolKey),disabled=!receiver;h+=`<tr><td>${(page-1)*pageSize+i+1}</td><td>${E(g.brand)}<br><small>${E(g.size)} · ${E(g.type)}</small></td><td>${E(g.code||'-')}</td><td class="p"><b>${E(g.sku)}</b><small>${F(g.stores.size)} ร้าน · ${F(g.bills.size)} บิล</small></td><td>${F(g.qty)}</td><td><input ${disabled?'disabled':''} class="pick jdata" data-map="send" data-k="${E(k)}" value="${N(send[k])||''}" type="number" inputmode="numeric"></td><td><input ${disabled?'disabled':''} class="pick jdata" data-map="add" data-k="${E(k)}" value="${N(add[k])||''}" type="number"></td><td><input ${disabled?'disabled':''} class="pick jdata" data-map="pull" data-k="${E(k)}" value="${N(pull[k])||''}" type="number"></td><td class="${remain(g)<0?'bad':'good'}">${F(remain(g))}</td><td>${B(g.amt)}</td></tr>`});if(!shown.length)h+='<tr><td colspan="10" class="empty">ไม่พบข้อมูล</td></tr>';return h+'</tbody>'}
function pager(total){const pages=Math.max(1,Math.ceil(total/pageSize));if(page>pages)page=pages;const p=$('#pager');if(!p)return;p.innerHTML=`<button class="page" data-p="${Math.max(1,page-1)}">‹</button><button class="page on">${page}/${pages}</button><button class="page" data-p="${Math.min(pages,page+1)}">›</button>`;$$('[data-p]').forEach(b=>b.onclick=()=>{page=N(b.dataset.p)||1;render()})}
function bindRows(){$$('.jdata').forEach(i=>i.onchange=e=>{const m=e.target.dataset.map,k=e.target.dataset.k;({send,add,pull}[m])[k]=N(e.target.value);saveState();render()})}
