function load(payload,m={}){meta=m||{};R=(payload?.rows||payload||[]).map(normalizeRow);window.__doitAllRows=R;key=meta.id||payload?.version_id||meta.file_name||'active';send={};add={};pull={};receiver='';filters={start:'',end:'',ps:'',brand:'',type:'',q:''};page=1;view='pick';const ds=dates();filters.start=ds[0]||'';filters.end=ds.at(-1)||'';loadState();boot();if($('#fileLabel'))$('#fileLabel').textContent='JSON Cloud: '+(meta.file_name||payload?.meta?.fileName||'latest');msg(`โหลด JSON/index สำเร็จ ${F(R.length)} แถว · Tele ${F(teleRows().length)} แถว`);render()}
